export const MEMORY_LEVELS = Array.from({ length: 20 }, (_, i) => {
  const level = i + 1;
  const count = Math.min(3 + Math.floor(level / 2), 10);
  const all = ['🐱','🐶','🐰','🦊','🐸','🐨','🐯','🐻','🦁','🐼','🦋','🐝','🐙','🦄','🐬','🦓','🦘','🦜','🦩','🐳'];
  return { level, pairs: count, emojis: all.slice(0, count), timeLimit: Math.max(60 - level * 2, 20) };
});

